    /**
     * Creates a secure OkHttpClient that enforces HTTPS for all connections.
     */
    private OkHttpClient createSecureClient() {
        return new OkHttpClient.Builder()
                .connectTimeout(CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .readTimeout(READ_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .writeTimeout(WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                // Enforce TLS-only connections - no cleartext HTTP allowed
                .connectionSpecs(java.util.Arrays.asList(
                        ConnectionSpec.MODERN_TLS,
                        ConnectionSpec.COMPATIBLE_TLS
                ))
                .followRedirects(false) // Prevent redirect from HTTPS to HTTP
                .followSslRedirects(false)
                .build();
    }

    /**
     * Validates that a URL uses HTTPS. Rejects all cleartext HTTP URLs.
     *
     * @param url The URL to validate
     * @throws SecurityException if the URL uses HTTP instead of HTTPS
     * @throws IllegalArgumentException if the URL is malformed
     */
    private void enforceHttps(String url) {
        if (url == null || url.isEmpty()) {
            throw new IllegalArgumentException("URL must not be null or empty");
        }

        String lowerUrl = url.toLowerCase().trim();

        if (lowerUrl.startsWith("http://")) {
            throw new SecurityException(
                    "Cleartext HTTP traffic is not permitted. Use HTTPS instead. "
                            + "URL: " + url + ". "
                            + "If connecting to a legacy device, use a secure gateway or upgrade the device firmware."
            );
        }

        if (!lowerUrl.startsWith("https://")) {
            throw new IllegalArgumentException(
                    "URL must use the HTTPS scheme. Got: " + url
            );
        }
    }

